#!/usr/bin/env node
// scaffold-day2a.mjs - Day 2a: hires 11 new agents into Headcount.
// Run from your headcount repo root: node scaffold-day2a.mjs
// Safe to re-run; overwrites files but does not delete anything.
//
// What this does:
//   1. Adds 11 new personality files in apps/orchestrator/src/seed/
//   2. Replaces apps/orchestrator/src/seed/seed.ts with one that hires all 12
//   3. Replaces apps/dashboard/app/page.tsx with one that shows the org chart
//
// After running this, do:
//   pnpm install   (only if it complains - probably not needed)
//   pnpm seed      (hires all 12 - idempotent, updates Eleanor in place)
//   pnpm orchestrator:dev   (still works, Eleanor still does the morning greeting)
//   pnpm dashboard:dev      (will now show the full org chart)

import { mkdirSync, writeFileSync } from 'node:fs';
import { dirname, resolve } from 'node:path';

const ROOT = process.cwd();

function writeFile(relPath, base64Content) {
  const full = resolve(ROOT, relPath);
  mkdirSync(dirname(full), { recursive: true });
  const bytes = Buffer.from(base64Content, 'base64');
  writeFileSync(full, bytes);
  console.log('  + ' + relPath);
}

console.log('');
console.log('Day 2a scaffold - hiring 11 new employees into Headcount');
console.log('Writing to: ' + ROOT);
console.log('');

writeFile('apps/dashboard/app/page.tsx', '');
writeFile('apps/orchestrator/src/seed/ayaka-hoshino.ts', '');
writeFile('apps/orchestrator/src/seed/bradley-koh.ts', '');
writeFile('apps/orchestrator/src/seed/chen-yuting.ts', '');
writeFile('apps/orchestrator/src/seed/evie-tan.ts', '');
writeFile('apps/orchestrator/src/seed/jaewon-han.ts', '');
writeFile('apps/orchestrator/src/seed/park-soyeon.ts', '');
writeFile('apps/orchestrator/src/seed/rina-halim.ts', '');
writeFile('apps/orchestrator/src/seed/seed.ts', '');
writeFile('apps/orchestrator/src/seed/siti-nurhaliza.ts', '');
writeFile('apps/orchestrator/src/seed/tessa-goh.ts', '');
writeFile('apps/orchestrator/src/seed/uncle-tan.ts', '');
writeFile('apps/orchestrator/src/seed/weiming-tsai.ts', '');

console.log('');
console.log('Done. Wrote 13 files.');
console.log('');
console.log('Next steps:');
console.log('  1. pnpm seed             (hires all 12 - idempotent)');
console.log('  2. pnpm orchestrator:dev (in one terminal)');
console.log('  3. pnpm dashboard:dev    (in another terminal)');
console.log('');
console.log('Then watch the org chart appear in the dashboard.');
console.log('Eleanor will still do the morning greeting at 09:00.');
console.log('Day 2b will add the chatter loop and DMs.');
console.log('');
